-- Script for DATA_DUMP_RPT_PAYMENT_MEDIA

-- Deletes existing properties to avoid unused extras
DELETE [IBC_ISSUER_FILE_TYPE_FIELDS]
WHERE ID_ISSUER = 999
AND ID_FILE_TYPE = (
    SELECT ID_FILE_TYPE
    FROM TFM_FILE_TYPE
    WHERE TYPE_NAME = 'DATA_DUMP_RPT_PAYMENT_MEDIA'
);

